import { Asset, AssetModalProps, GetAssets, GetUsers } from "./common";
export interface ChooseAssetModalProps extends AssetModalProps {
    /**
     * Function called once the user confirms the selection
     * @param assets {Asset[]} the selected assets
     * @returns void
     */
    onSubmit: (assets: Asset[]) => void;
    /**
       * Determines the Asset UIDs to be excluded
       * This is passed to `getAssets`
       */
    excludeAssetUids?: string[];
    initiallySelectedAssets?: string[];
    getAssets: GetAssets;
    getUsers?: GetUsers;
    vendor?: 'asset_management' | string;
    modalTitle?: string;
    modalApplyButtonText?: string;
    isFolderSelection?: boolean;
    showUserDataColumn?: boolean;
    showCTAIcon?: boolean;
    hasBranchFeature?: boolean;
    multiBranchInfo?: string;
}
